1	<?php
2	
3	declare(strict_types=1);
4	
5	namespace VeloCMS\Modules\Translation\Services;
6	
7	use VeloCMS\Core\Services\TranslationService;
8	use VeloCMS\Modules\Translation\Models\TranslationModel;
9	
10	class TranslationEngine
11	{
12	    private TranslationModel $model;
13	    private TranslationService $service;
14	    private string $defaultLang;
15	    /** @var string[] */
16	    private array $targetLangs;
17	
18	    public function __construct()
19	    {
20	        $this->model   = new TranslationModel();
21	        $this->service = new TranslationService();
22	
23	        $activeLangs       = json_decode(setting('active_languages', '["de","en"]'), true) ?: ['de', 'en'];
24	        $this->defaultLang = setting('default_language', 'de');
25	        $this->targetLangs = array_values(array_filter(
26	            $activeLangs,
27	            fn(string $l) => $l !== $this->defaultLang
28	        ));
29	    }
30	
31	    /**
32	     * Translate all UI strings from lang/en.php into every active non-default language
33	     * that has no static lang/{lang}.php file. Results are cached in velocms_translations
34	     * with table_name='velocms_ui' and row_id=0.
35	     */
36	    public function translateUiStrings(): void
37	    {
38	        $enPath = BASE_PATH . '/lang/en.php';
39	        if (!file_exists($enPath)) {
40	            return;
41	        }
42	
43	        $strings = require $enPath;
44	        if (!is_array($strings)) {
45	            return;
46	        }
47	
48	        foreach ($this->targetLangs as $lang) {
49	            if (file_exists(BASE_PATH . "/lang/{$lang}.php")) {
50	                continue;
51	            }
52	            try {
53	                $this->translateUiIntoLang($strings, $lang);
54	            } catch (\Throwable $e) {
55	                error_log('[TranslationEngine] UI lang=' . $lang . ': ' . $e->getMessage());
56	            }
57	        }
58	    }
59	
60	    /** @param array<string,string> $strings */
61	    private function translateUiIntoLang(array $strings, string $lang): void
62	    {
63	        $pending     = [];
64	        $pendingKeys = [];
65	
66	        foreach ($strings as $key => $text) {
67	            if (!is_string($key) || !is_string($text) || trim($text) === '') {
68	                continue;
69	            }
70	
71	            $existing = $this->model->get('velocms_ui', 0, $key, $lang);
72	            if ($existing && $existing['source'] === 'manual') {
73	                continue;
74	            }
75	
76	            $hash = md5($text);
77	            if ($existing && $existing['content_hash'] === $hash) {
78	                continue;
79	            }
80	
81	            $pending[]     = $text;
82	            $pendingKeys[] = [$key, $hash];
83	        }
84	
85	        if (empty($pending)) {
86	            return;
87	        }
88	
89	        // Translate in chunks of 50 to stay within API limits
90	        foreach (array_chunk($pending, 50) as $ci => $chunk) {
91	            $keyChunk   = array_slice($pendingKeys, $ci * 50, 50);
92	            $translated = $this->service->translateBatch($chunk, strtoupper($lang), 'EN');
93	
94	            foreach ($keyChunk as $i => [$key, $hash]) {
95	                $this->model->upsert('velocms_ui', 0, $key, $lang, $translated[$i], 'auto', $hash);
96	            }
97	        }
98	    }
99	
100	    /**
101	     * Translate all given fields for a DB row into every active non-default language.
102	     *
103	     * @param string            $table  DB table name (e.g. 'velocms_blog_posts')
104	     * @param int               $rowId  Primary key of the row
105	     * @param array<string,string> $fields field => source-text map
106	     */
107	    public function translateRow(string $table, int $rowId, array $fields, bool $force = false): void
108	    {
109	        foreach ($this->targetLangs as $lang) {
110	            try {
111	                $this->translateRowIntoLang($table, $rowId, $fields, $lang, $force);
112	            } catch (\Throwable $e) {
113	                error_log('[TranslationEngine] lang=' . $lang . ' table=' . $table
114	                    . ' id=' . $rowId . ': ' . $e->getMessage());
115	            }
116	        }
117	    }
118	
119	    /** @param array<string,string> $fields */
120	    private function translateRowIntoLang(string $table, int $rowId, array $fields, string $lang, bool $force = false): void
121	    {
122	        $pending     = [];
123	        $pendingKeys = [];
124	
125	        foreach ($fields as $field => $text) {
126	            if (trim($text) === '') {
127	                continue;
128	            }
129	
130	            $existing = $this->model->get($table, $rowId, $field, $lang);
131	            $hash     = md5($text);
132	
133	            if (!$force && $existing && $existing['content_hash'] === $hash) {
134	                continue;
135	            }
136	
137	            $pending[]     = $text;
138	            $pendingKeys[] = [$field, $hash];
139	        }
140	
141	        if (empty($pending)) {
142	            return;
143	        }
144	
145	        $translated = $this->service->translateBatch(
146	            $pending,
147	            strtoupper($lang),
148	            strtoupper($this->defaultLang)
149	        );
150	
151	        foreach ($pendingKeys as $i => [$field, $hash]) {
152	            $this->model->upsert($table, $rowId, $field, $lang, $translated[$i], 'auto', $hash);
153	        }
154	    }
155	}
