3	declare(strict_types=1);
4	
5	namespace VeloCMS\Core\Services;
6	
7	/**
8	 * Thrown when all configured translation providers fail.
9	 */
10	class TranslationException extends \RuntimeException {}
11	
12	/**
13	 * Low-level translation service.
14	 * Tries DeepL first, falls back to Anthropic Claude.
15	 *
16	 * Configuration (in .env):
17	 *   DEEPL_API_KEY   — DeepL free or pro API key
18	 *   ANTHROPIC_API_KEY — Anthropic API key (fallback)
19	 *
20	 * For pro DeepL accounts, change the endpoint in translateWithDeepL()
21	 * from api-free.deepl.com to api.deepl.com.
22	 */
23	class TranslationService
24	{
25	    /**
26	     * Translate multiple texts in a single API call.
27	     *
28	     * @param  string[] $texts      Texts to translate (preserves order)
29	     * @param  string   $targetLang e.g. 'EN', 'FR'
30	     * @param  string   $sourceLang e.g. 'DE'
31	     * @return string[]             Translated texts in the same order
32	     * @throws TranslationException When all providers fail
33	     */
34	    public function translateBatch(
35	        array $texts,
36	        string $targetLang,
37	        string $sourceLang = 'DE',
38	        array $options = []
39	    ): array {
40	        if (empty($texts)) {
41	            return [];
42	        }
43	
44	        $deeplError = null;
45	
46	        try {
47	            return $this->translateBatchWithDeepL($texts, $targetLang, $sourceLang, $options);
48	        } catch (TranslationException $e) {
49	            $deeplError = $e->getMessage();
50	            error_log('[TranslationService] DeepL batch failed, trying Anthropic. Reason: ' . $deeplError);
51	        }
52	
53	        try {
54	            return $this->translateBatchWithAnthropic($texts, $targetLang, $sourceLang);
55	        } catch (TranslationException $e) {
56	            throw new TranslationException(
57	                'All translation providers failed. DeepL: ' . $deeplError
58	                . ' | Anthropic: ' . $e->getMessage()
59	            );
60	        }
61	    }
62	
63	    // ── DeepL ────────────────────────────────────────────────────────────────
64	
65	    private function translateBatchWithDeepL(
66	        array $texts,
67	        string $targetLang,
68	        string $sourceLang,
69	        array $options
70	    ): array {
71	        $envKey = $_ENV['DEEPL_API_KEY'] ?? $_ENV['DEEPL_KEY'] ?? '';
72	        $key    = $envKey !== '' ? $envKey : setting('deepl_api_key', '');
73	
74	        if (empty($key)) {
75	            throw new TranslationException('No DeepL API key configured. Add DEEPL_API_KEY to .env or enter it in Translation Settings.');
76	        }
77	
78	        $target = strtoupper($targetLang);
79	        if ($target === 'EN') {
80	            $target = 'EN-GB';
81	        }
82	
83	        $params = [
84	            'text'        => $texts,
85	            'source_lang' => strtoupper($sourceLang),
86	            'target_lang' => $target,
87	        ];
88	
89	        if (!empty($options['glossary_id'])) {
90	            $params['glossary_id'] = (string) $options['glossary_id'];
91	        }
92	
93	        $response = $this->httpPost(
94	            'https://api-free.deepl.com/v2/translate',
95	            (string) json_encode($params),
96	            [
97	                'Authorization: DeepL-Auth-Key ' . $key,
98	                'Content-Type: application/json',
99	            ]
100	        );
101	
102	        $data = json_decode($response, true);
103	
104	        if (!isset($data['translations']) || !is_array($data['translations'])) {
105	            throw new TranslationException('Unexpected DeepL response: ' . $response);
106	        }
107	
108	        return array_map(fn(array $t): string => (string) $t['text'], $data['translations']);
109	    }
110	
111	    private function translateBatchWithAnthropic(
112	        array $texts,
113	        string $targetLang,
114	        string $sourceLang
115	    ): array {
116	        $envKey = $_ENV['ANTHROPIC_API_KEY'] ?? $_ENV['ANTHROPIC_KEY'] ?? '';
117	        $key    = $envKey !== '' ? $envKey : setting('anthropic_api_key', '');
118	
119	        if (empty($key)) {
120	            throw new TranslationException('No Anthropic API key configured. Add ANTHROPIC_API_KEY to .env or enter it in Translation Settings.');
121	        }
122	
123	        $langNames = [
124	            'DE' => 'German',     'EN' => 'English',    'FR' => 'French',
125	            'ES' => 'Spanish',    'IT' => 'Italian',    'NL' => 'Dutch',
126	            'PL' => 'Polish',     'PT' => 'Portuguese', 'RU' => 'Russian',
127	            'JA' => 'Japanese',   'ZH' => 'Chinese',    'TR' => 'Turkish',
128	        ];
129	
130	        $from = $langNames[strtoupper($sourceLang)] ?? strtoupper($sourceLang);
131	        $to   = $langNames[strtoupper($targetLang)] ?? strtoupper($targetLang);
132	
133	        $prompt = "Translate each string in this JSON array from {$from} to {$to}. "
134	                . "Return ONLY a valid JSON array with the translated strings in the same order. "
135	                . "No explanations, no markdown, just the JSON array:\n\n"
136	                . json_encode($texts);
137	
138	        $payload = (string) json_encode([
139	            'model'      => 'claude-haiku-4-5-20251001',
140	            'max_tokens' => 4096,
141	            'messages'   => [[
142	                'role'    => 'user',
143	                'content' => $prompt,
144	            ]],
145	        ]);
146	
147	        $response = $this->httpPost(
148	            'https://api.anthropic.com/v1/messages',
149	            $payload,
150	            [
151	                'x-api-key: '          . $key,
152	                'anthropic-version: 2023-06-01',
153	                'content-type: application/json',
154	            ]
155	        );
156	
157	        $data = json_decode($response, true);
158	
159	        if (!isset($data['content'][0]['text'])) {
160	            throw new TranslationException('Unexpected Anthropic response: ' . $response);
161	        }
162	
163	        $result = json_decode((string) $data['content'][0]['text'], true);
164	
165	        if (!is_array($result) || count($result) !== count($texts)) {
166	            throw new TranslationException('Anthropic batch response did not return matching array');
167	        }
168	
169	        return array_map('strval', $result);
170	    }
171	
172	    // ── HTTP helper ───────────────────────────────────────────────────────────
173	
174	    private function httpPost(string $url, string $body, array $headers = []): string
175	    {
176	        if (!function_exists('curl_init')) {
177	            throw new TranslationException('cURL extension is not available');
178	        }
179	
180	        $ch = curl_init($url);
181	
182	        curl_setopt_array($ch, [
183	            CURLOPT_POST           => true,
184	            CURLOPT_POSTFIELDS     => $body,
185	            CURLOPT_RETURNTRANSFER => true,
186	            CURLOPT_HTTPHEADER     => $headers,
187	            CURLOPT_TIMEOUT        => 20,
188	            CURLOPT_CONNECTTIMEOUT => 5,
189	            CURLOPT_SSL_VERIFYPEER => true,
190	        ]);
191	
192	        $response = curl_exec($ch);
193	        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
194	        $error    = curl_error($ch);
195	        curl_close($ch);
196	
197	        if ($response === false) {
198	            throw new TranslationException("cURL request failed: {$error}");
199	        }
200	
201	        if ($httpCode >= 400) {
202	            throw new TranslationException(
203	                "HTTP {$httpCode} from " . parse_url($url, PHP_URL_HOST) . ": {$response}"
204	            );
205	        }
206	
207	        return (string) $response;
208	    }
209	}
