3	declare(strict_types=1);
4	
5	namespace VeloCMS\Modules\Translation\Models;
6	
7	use VeloCMS\Core\Database;
8	
9	class TranslationModel
10	{
11	    private \PDO $db;
12	
13	    public function __construct()
14	    {
15	        $this->db = Database::getInstance()->getPdo();
16	    }
17	
18	    public function get(string $table, int $rowId, string $field, string $lang): ?array
19	    {
20	        $stmt = $this->db->prepare(
21	            'SELECT * FROM velocms_translations
22	             WHERE table_name = :t AND row_id = :r AND field = :f AND language = :l
23	             LIMIT 1'
24	        );
25	        $stmt->execute([':t' => $table, ':r' => $rowId, ':f' => $field, ':l' => $lang]);
26	        return $stmt->fetch(\PDO::FETCH_ASSOC) ?: null;
27	    }
28	
29	    public function upsert(
30	        string $table,
31	        int    $rowId,
32	        string $field,
33	        string $lang,
34	        string $value,
35	        string $source = 'auto',
36	        string $hash   = ''
37	    ): void {
38	        $stmt = $this->db->prepare(
39	            'INSERT INTO velocms_translations
40	             (table_name, row_id, field, language, value, source, stale, content_hash, translated_at)
41	             VALUES (:t, :r, :f, :l, :v, :s, 0, :h, NOW())
42	             ON DUPLICATE KEY UPDATE
43	                 value         = VALUES(value),
44	                 source        = VALUES(source),
45	                 stale         = 0,
46	                 content_hash  = VALUES(content_hash),
47	                 translated_at = NOW()'
48	        );
49	        $stmt->execute([
50	            ':t' => $table,
51	            ':r' => $rowId,
52	            ':f' => $field,
53	            ':l' => $lang,
54	            ':v' => $value,
55	            ':s' => $source,
56	            ':h' => $hash,
57	        ]);
58	    }
59	
60	    /** Returns field => value map for a row in the given language. */
61	    public function getForRow(string $table, int $rowId, string $lang): array
62	    {
63	        $stmt = $this->db->prepare(
64	            'SELECT field, value FROM velocms_translations
65	             WHERE table_name = :t AND row_id = :r AND language = :l'
66	        );
67	        $stmt->execute([':t' => $table, ':r' => $rowId, ':l' => $lang]);
68	        return $stmt->fetchAll(\PDO::FETCH_KEY_PAIR) ?: [];
69	    }
70	
71	    /** Stats for the dashboard: total, auto_ok, manual_ok, stale. */
72	    public function getStats(string $lang): array
73	    {
74	        $stmt = $this->db->prepare(
75	            'SELECT
76	                COUNT(*) AS total,
77	                SUM(source = "auto"   AND stale = 0) AS auto_ok,
78	                SUM(source = "manual" AND stale = 0) AS manual_ok,
79	                SUM(stale = 1) AS stale
80	             FROM velocms_translations WHERE language = :l'
81	        );
82	        $stmt->execute([':l' => $lang]);
83	        return $stmt->fetch(\PDO::FETCH_ASSOC)
84	            ?: ['total' => 0, 'auto_ok' => 0, 'manual_ok' => 0, 'stale' => 0];
85	    }
86	
87	    /** Paginated list with optional filters. */
88	    public function getList(
89	        string $lang,
90	        string $table  = '',
91	        string $source = '',
92	        int    $limit  = 25,
93	        int    $offset = 0
94	    ): array {
95	        [$where, $params] = $this->buildWhere($lang, $table, $source);
96	        $stmt = $this->db->prepare(
97	            "SELECT * FROM velocms_translations {$where}
98	             ORDER BY stale DESC, translated_at ASC
99	             LIMIT :lim OFFSET :off"
100	        );
101	        foreach ($params as $k => $v) {
102	            $stmt->bindValue($k, $v);
103	        }
104	        $stmt->bindValue(':lim', $limit, \PDO::PARAM_INT);
105	        $stmt->bindValue(':off', $offset, \PDO::PARAM_INT);
106	        $stmt->execute();
107	        return $stmt->fetchAll(\PDO::FETCH_ASSOC) ?: [];
108	    }
109	
110	    public function countList(string $lang, string $table = '', string $source = ''): int
111	    {
112	        [$where, $params] = $this->buildWhere($lang, $table, $source);
113	        $stmt = $this->db->prepare(
114	            "SELECT COUNT(*) FROM velocms_translations {$where}"
115	        );
116	        $stmt->execute($params);
117	        return (int) $stmt->fetchColumn();
118	    }
119	
120	    /** Distinct table names that have translation rows. */
121	    public function getTables(): array
122	    {
123	        return $this->db->query(
124	            'SELECT DISTINCT table_name FROM velocms_translations ORDER BY table_name'
125	        )->fetchAll(\PDO::FETCH_COLUMN) ?: [];
126	    }
127	
128	    public function getById(int $id): ?array
129	    {
130	        $stmt = $this->db->prepare(
131	            'SELECT * FROM velocms_translations WHERE id = :id LIMIT 1'
132	        );
133	        $stmt->execute([':id' => $id]);
134	        return $stmt->fetch(\PDO::FETCH_ASSOC) ?: null;
135	    }
136	
137	    /** Save a manually edited translation and lock it against auto-overwrite. */
138	    public function updateManual(int $id, string $value): void
139	    {
140	        $stmt = $this->db->prepare(
141	            'UPDATE velocms_translations
142	             SET value = :v, source = "manual", stale = 0, translated_at = NOW()
143	             WHERE id = :id'
144	        );
145	        $stmt->execute([':v' => $value, ':id' => $id]);
146	    }
147	
148	    /** Release a manual lock so the next content save will re-translate it. */
149	    public function unlock(int $id): void
150	    {
151	        $stmt = $this->db->prepare(
152	            'UPDATE velocms_translations SET source = "auto", stale = 1 WHERE id = :id'
153	        );
154	        $stmt->execute([':id' => $id]);
155	    }
156	
157	    /** @return array{0: string, 1: array<string,mixed>} */
158	    private function buildWhere(string $lang, string $table, string $source): array
159	    {
160	        $where  = 'WHERE language = :l';
161	        $params = [':l' => $lang];
162	
163	        if ($table !== '') {
164	            $where       .= ' AND table_name = :t';
165	            $params[':t'] = $table;
166	        }
167	
168	        match ($source) {
169	            'stale'  => $where .= ' AND stale = 1',
170	            'manual' => $where .= ' AND source = "manual"',
171	            'auto'   => $where .= ' AND source = "auto" AND stale = 0',
172	            default  => null,
173	        };
174	
175	        return [$where, $params];
176	    }
177	}
