3	declare(strict_types=1);
4	
5	namespace VeloCMS\Modules\Translation\Controllers;
6	
7	use VeloCMS\Core\Auth;
8	use VeloCMS\Core\Controller;
9	use VeloCMS\Core\Database;
10	use VeloCMS\Modules\Translation\Models\TranslationModel;
11	
12	class AdminTranslationController extends Controller
13	{
14	    private TranslationModel $model;
15	    /** @var string[] */
16	    private array $activeLangs;
17	    private string $defaultLang;
18	    /** @var string[] */
19	    private array $targetLangs;
20	
21	    public function __construct()
22	    {
23	        parent::__construct();
24	        $this->requireAuth();
25	        $this->requireRole('admin');
26	
27	        $this->model       = new TranslationModel();
28	        $this->activeLangs = json_decode(setting('active_languages', '["de","en"]'), true) ?: ['de', 'en'];
29	        $this->defaultLang = setting('default_language', 'de');
30	        $this->targetLangs = array_values(array_filter(
31	            $this->activeLangs,
32	            fn(string $l) => $l !== $this->defaultLang
33	        ));
34	    }
35	
36	    public function dashboard(): void
37	    {
38	        $stats = [];
39	        foreach ($this->targetLangs as $lang) {
40	            $stats[$lang] = $this->model->getStats($lang);
41	        }
42	
43	        $this->render('admin/translation/dashboard', [
44	            'stats'       => $stats,
45	            'targetLangs' => $this->targetLangs,
46	            'defaultLang' => $this->defaultLang,
47	        ]);
48	    }
49	
50	    public function editor(): void
51	    {
52	        $lang    = $this->sanitizeLang($this->input('lang', $this->targetLangs[0] ?? 'en'));
53	        $table   = (string) $this->input('table', '');
54	        $source  = (string) $this->input('source', '');
55	        $editId  = (int) $this->input('edit', 0);
56	        $page    = max(1, (int) $this->input('page', 1));
57	        $perPage = 25;
58	        $offset  = ($page - 1) * $perPage;
59	
60	        $rows   = $this->model->getList($lang, $table, $source, $perPage, $offset);
61	        $total  = $this->model->countList($lang, $table, $source);
62	        $tables = $this->model->getTables();
63	        $pages  = (int) ceil($total / $perPage);
64	
65	        $editRow = $editId > 0 ? $this->model->getById($editId) : null;
66	
67	        $this->render('admin/translation/editor', [
68	            'rows'        => $rows,
69	            'total'       => $total,
70	            'page'        => $page,
71	            'pages'       => $pages,
72	            'perPage'     => $perPage,
73	            'tables'      => $tables,
74	            'targetLangs' => $this->targetLangs,
75	            'lang'        => $lang,
76	            'table'       => $table,
77	            'source'      => $source,
78	            'editRow'     => $editRow,
79	            'editId'      => $editId,
80	        ]);
81	    }
82	
83	    public function saveTranslation(string $id): void
84	    {
85	        Auth::verifyCsrf();
86	        $row = $this->model->getById((int) $id);
87	        if (!$row) {
88	            $this->redirectWithError('/admin/apps/translation/editor', t('error.not_found'));
89	        }
90	        $this->model->updateManual((int) $id, (string) $this->input('value', ''));
91	        $qs = $this->buildEditorQs($row['language'], $row['table_name']);
92	        $this->redirectWithSuccess('/admin/apps/translation/editor?' . $qs, t('success.saved'));
93	    }
94	
95	    public function unlockTranslation(string $id): void
96	    {
97	        Auth::verifyCsrf();
98	        $row = $this->model->getById((int) $id);
99	        if (!$row) {
100	            $this->redirectWithError('/admin/apps/translation/editor', t('error.not_found'));
101	        }
102	        $this->model->unlock((int) $id);
103	        $qs = $this->buildEditorQs($row['language'], $row['table_name']);
