118	    public function saveSettings(): void
119	    {
120	        Auth::verifyCsrf();
121	
122	        $knownLangs = [
123	            'ar','bg','cs','da','de','el','en','es','et','fi','fr',
124	            'hu','id','it','ja','ko','lt','lv','nb','nl','pl',
125	            'pt','ro','ru','sk','sl','sr','sv','tr','uk','zh',
126	        ];
127	        $selected   = array_filter(
128	            (array) ($_POST['active_languages'] ?? []),
129	            fn(string $l) => in_array($l, $knownLangs, true)
130	        );
131	        if (empty($selected)) {
132	            $this->redirectWithError('/admin/apps/translation/settings', t('error.required'));
133	        }
134	        $selected = array_values($selected);
135	
136	        $default = trim((string) $this->input('default_language', 'de'));
137	        if (!in_array($default, $selected, true)) {
138	            $default = $selected[0];
139	        }
140	
141	        $provider = $this->input('translation_provider', 'deepl');
142	        if (!in_array($provider, ['deepl', 'anthropic'], true)) {
143	            $provider = 'deepl';
144	        }
145	
146	        $this->saveSetting('active_languages', json_encode($selected));
147	        $this->saveSetting('default_language', $default);
148	        $this->saveSetting('translation_provider', $provider);
149	
150	        $deeplKey = trim((string) $this->input('deepl_api_key', ''));
151	        if ($deeplKey !== '') {
152	            $this->saveSetting('deepl_api_key', $deeplKey);
153	        }
