168	    private function saveSetting(string $key, string $value): void
169	    {
170	        $db   = Database::getInstance()->getPdo();
171	        $stmt = $db->prepare(
172	            'INSERT INTO velocms_settings (`key`, value) VALUES (:k, :v)
173	             ON DUPLICATE KEY UPDATE value = :v2'
174	        );
175	        $stmt->execute([':k' => $key, ':v' => $value, ':v2' => $value]);
176	    }
