85	        'ID':'Indonesisch','IT':'Italienisch','JA':'Japanisch','KO':'Koreanisch',
86	        'LT':'Litauisch','LV':'Lettisch','NB':'Norwegisch','NL':'Niederländisch',
87	        'PL':'Polnisch','PT':'Portugiesisch','RO':'Rumänisch','RU':'Russisch',
88	        'SK':'Slowakisch','SL':'Slowenisch','SR':'Serbisch','SV':'Schwedisch',
89	        'TR':'Türkisch','UK':'Ukrainisch','ZH':'Chinesisch'
90	    };
91	
92	    const DEFAULT_LANG  = '<?= strtoupper(e($defaultLang)) ?>';
93	    const initial       = <?= json_encode(array_map('strtoupper', $activeLangs)) ?>;
