125	    private function collectData(array $existing = []): array
126	    {
127	        $slug = $this->sanitizeSlug($this->input('slug', $existing['slug'] ?? ''));
128	        return [
129	            'title'            => $this->input('title', ''),
130	            'title_en'         => $this->input('title_en', ''),
131	            'slug'             => $slug,
132	            'excerpt'          => $this->input('excerpt', null),
133	            'excerpt_en'       => $this->input('excerpt_en', null),
134	            'content'          => $this->input('content', ''),
135	            'content_en'       => $this->input('content_en', ''),
136	            'cover_image'      => $this->input('cover_image', ''),
137	            'status'           => $this->input('status', 'draft'),
138	            'meta_title'       => $this->input('meta_title', ''),
139	            'meta_description' => $this->input('meta_description', ''),
140	            'author_id'        => Auth::id() ?? 1,
141	            'published_at'     => $existing['published_at'] ?? null,
142	        ];
143	    }
