145	    /** @return array{0: string[], 1: string, 2: array<string, array<string,string>>} */
146	    private function loadTranslations(int $postId): array
147	    {
148	        $activeLangs = json_decode(setting('active_languages', '["de","en"]'), true) ?: ['de', 'en'];
149	        $defaultLang = setting('default_language', 'de');
150	        $targetLangs = array_values(array_filter(
151	            $activeLangs,
152	            fn(string $l) => $l !== $defaultLang
153	        ));
154	
155	        $transModel   = new TranslationModel();
156	        $translations = [];
157	        foreach ($targetLangs as $lang) {
158	            $translations[$lang] = $transModel->getForRow('velocms_blog_posts', $postId, $lang);
159	        }
160	
161	        return [$targetLangs, $defaultLang, $translations];
162	    }
163	
164	    /** @param array<string,string> $sourceFields The current DE source fields (title/excerpt/content) */
165	    private function saveManualTranslations(int $postId, array $sourceFields): void
166	    {
167	        $submitted = $_POST['trans'] ?? [];
168	        if (empty($submitted) || !is_array($submitted)) {
169	            return;
170	        }
171	
172	        $transModel = new TranslationModel();
173	
174	        foreach ($submitted as $lang => $fields) {
175	            if (!is_array($fields) || !preg_match('/^[a-z]{2}$/', (string) $lang)) {
176	                continue;
177	            }
178	            foreach (['title', 'excerpt', 'content'] as $field) {
179	                $val = trim((string) ($fields[$field] ?? ''));
180	                if ($val === '') {
181	                    continue;
182	                }
183	                $existing = $transModel->get('velocms_blog_posts', $postId, $field, $lang);
184	                if ($existing === null || trim($existing['value']) !== $val) {
185	                    $sourceText = trim((string) ($sourceFields[$field] ?? ''));
186	                    $transModel->upsert(
187	                        'velocms_blog_posts', $postId, $field, $lang,
188	                        $val, 'manual', $sourceText !== '' ? md5($sourceText) : ''
189	                    );
190	                }
191	            }
192	        }
193	    }
194	
195	    /** @return array<string,string> */
196	    private function collectTranslatableFields(): array
197	    {
198	        return [
199	            'title'   => (string) $this->input('title', ''),
200	            'excerpt' => (string) $this->input('excerpt', ''),
201	            'content' => (string) $this->input('content', ''),
202	        ];
203	    }
204	
205	    private function sanitizeSlug(string $raw): string
206	    {
207	        $slug = mb_strtolower(trim($raw));
208	        $slug = preg_replace('/[^a-z0-9\-]/', '-', $slug);
209	        $slug = preg_replace('/-+/', '-', $slug);
210	        return trim($slug, '-');
211	    }
212	}
