16	    {
17	        $parts    = explode('\\', static::class);
18	        $moduleIdx = array_search('Modules', $parts);
19	
20	        if ($moduleIdx !== false && isset($parts[$moduleIdx + 1])) {
21	            $moduleName = $parts[$moduleIdx + 1];
22	            $viewPath   = BASE_PATH . "/modules/{$moduleName}/views/{$view}.php";
23	        } else {
24	            $viewPath = BASE_PATH . "/views/{$view}.php";
25	        }
26	
27	        if (!file_exists($viewPath)) {
28	            throw new \RuntimeException("View not found: {$view} (looked in: {$viewPath})");
29	        }
30	
31	        $this->view->renderFile($viewPath, $data);
32	    }
