52	    /**
53	     * Redirect immediately, then run $callback in the background after the response is flushed.
54	     * Requires fastcgi_finish_request() (PHP-FPM) — falls back to running callback before exit.
55	     */
56	    protected function redirectWithSuccessAndBackground(
57	        string $url,
58	        string $message,
59	        callable $callback
60	    ): never {
61	        $_SESSION['flash_success'] = $message;
62	        session_write_close();
63	        header('Location: ' . $url);
64	
65	        if (function_exists('fastcgi_finish_request')) {
66	            fastcgi_finish_request();
67	        }
68	
69	        set_time_limit(0);
70	        $callback();
71	        exit;
72	    }
