5	/**
6	 * Escape output — always use for user data in views
7	 */
8	function e(mixed $value): string
9	{
10	    return htmlspecialchars((string) $value, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8');
11	}
12	
13	/**
14	 * Get translation string — Layer 1 UI strings
15	 */
16	function t(string $key, array $params = []): string
17	{
18	    static $strings = null;
19	
20	    if ($strings === null) {
21	        $isAdmin = str_starts_with($_SERVER['REQUEST_URI'] ?? '/', '/admin');
22	        $lang    = $isAdmin
23	            ? ($_COOKIE['vcms_admin_lang'] ?? $_COOKIE['vcms_lang'] ?? 'de')
24	            : ($_COOKIE['vcms_lang'] ?? 'de');
25	        $lang = preg_match('/^[a-z]{2}$/', $lang) ? $lang : 'de';
26	
27	        $dePath   = BASE_PATH . '/lang/de.php';
28	        $enPath   = BASE_PATH . '/lang/en.php';
29	        $langPath = BASE_PATH . "/lang/{$lang}.php";
30	
31	        $de = file_exists($dePath) ? require $dePath : [];
32	        $en = file_exists($enPath) ? require $enPath : [];
33	
34	        if ($lang === 'de') {
35	            $strings = $de;
36	        } elseif ($lang === 'en') {
37	            $strings = array_merge($de, $en);
38	        } elseif (file_exists($langPath)) {
39	            $strings = array_merge($de, require $langPath);
40	        } else {
41	            // Start with EN fallback, then overlay DB-cached UI translations
42	            $strings = array_merge($de, $en);
43	            try {
44	                $db   = \VeloCMS\Core\Database::getInstance()->getPdo();
45	                $stmt = $db->prepare(
46	                    "SELECT field, value FROM velocms_translations
47	                     WHERE table_name = 'velocms_ui' AND row_id = 0
48	                       AND language = :l AND stale = 0"
49	                );
50	                $stmt->execute([':l' => $lang]);
51	                $ui = $stmt->fetchAll(\PDO::FETCH_KEY_PAIR);
52	                if (!empty($ui)) {
53	                    $strings = array_merge($strings, $ui);
54	                }
55	            } catch (\Throwable) {
56	                // DB not yet available — English fallback stays
57	            }
58	        }
59	    }
60	
61	    $text = $strings[$key] ?? $key;
62	
63	    foreach ($params as $param => $value) {
64	        $text = str_replace(':' . $param, (string) $value, $text);
65	    }
66	
67	    return $text;
68	}
