70	/**
71	 * Get localized content field — Layer 2 DB content.
72	 * Pass $table to look up velocms_translations first (Phase 3+).
73	 * Falls back to legacy _en columns for backward compatibility.
74	 */
75	function localized(array $row, string $field, string $table = ''): string
76	{
77	    static $cache = [];
78	
79	    $isAdmin     = str_starts_with($_SERVER['REQUEST_URI'] ?? '/', '/admin');
80	    $lang        = $isAdmin
81	        ? ($_COOKIE['vcms_admin_lang'] ?? $_COOKIE['vcms_lang'] ?? 'de')
82	        : ($_COOKIE['vcms_lang'] ?? 'de');
83	    $defaultLang = setting('default_language', 'de');
84	
85	    if ($lang === $defaultLang) {
86	        return (string) ($row[$field] ?? '');
87	    }
88	
89	    if ($table !== '' && !empty($row['id'])) {
90	        $key = $table . ':' . $row['id'] . ':' . $field . ':' . $lang;
91	        if (!array_key_exists($key, $cache)) {
92	            try {
93	                $db   = \VeloCMS\Core\Database::getInstance()->getPdo();
94	                $stmt = $db->prepare(
95	                    'SELECT value FROM velocms_translations
96	                     WHERE table_name = :t AND row_id = :r AND field = :f AND language = :l AND stale = 0
97	                     LIMIT 1'
98	                );
99	                $stmt->execute([':t' => $table, ':r' => (int) $row['id'], ':f' => $field, ':l' => $lang]);
100	                $val          = $stmt->fetchColumn();
101	                $cache[$key]  = ($val !== false && $val !== '') ? (string) $val : null;
102	            } catch (\Throwable) {
103	                $cache[$key] = null;
104	            }
105	        }
106	        if ($cache[$key] !== null) {
107	            return $cache[$key];
108	        }
109	    }
110	
111	    $enField = $field . '_en';
112	    if (!empty($row[$enField])) {
113	        return (string) $row[$enField];
114	    }
115	
116	    return (string) ($row[$field] ?? '');
117	}
